('99846eba-083d-4f55-ac8b-85d5d2acc958', 'Burrata Salad', 'Salads', 'capiche', null, null, null, 1, 'approved', 164.65, 164.65, 620, 0, 5, false, 250, 'Gram', 1, ARRAY['Toss leaves with vinaigrette & salt.','Add cherry tomato, grapefruit, olives.','Place burrata in centre.','Arrange salad mix around.','Sprinkle pine nuts; drizzle olive oil & hot honey.','Garnish with edible flowers.']::text[], null, null, '2026-06-20T09:30:00.000Z', null, '2026-06-01T09:00:00.000Z', '2026-06-01T09:00:00.000Z'),
